      setup.DBI_pass ? "PASS" : "FAIL",
      setup.MPS_pass ? "PASS" : "FAIL",
      setup.allFiltersPass ? "PASS" : "FAIL",
      setup.breakoutOccurred ? "YES" : "NO",
      setup.breakoutDirection == 1 ? "LONG" : (setup.breakoutDirection == -1 ? "SHORT" : "NONE"),
      DoubleToString(setup.breakoutPrice, _Digits),
      IntegerToString(setup.barsToBreakout),
      DoubleToString(setup.entryPrice, _Digits),
      DoubleToString(setup.TP, _Digits),
