         " to ", TimeToString(iTime(_Symbol, PERIOD_M5, 0)));

   // Prepare CSV file
   string filename = InpCSVFilename + "_" + _Symbol + ".csv";
   int handle = FileOpen(filename, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(handle == INVALID_HANDLE)
   {
      Print("ERROR: Cannot create CSV file: ", filename);
      return;
   }

   // Write CSV header
   FileWrite(handle,
      "SetupTime", "Session", "DayOfWeek", "DayName",
      "RangeHigh", "RangeLow", "RangeSize", "RangeOpen", "RangeClose",
      "ATR", "RCR", "DBI", "MPS",
      "RCR_Pass", "DBI_Pass", "MPS_Pass", "AllFiltersPass",
      "BreakoutOccurred", "BreakoutDir", "BreakoutPrice", "BarsToBreakout",
      "EntryPrice", "TP", "SL", "ExitPrice", "ExitReason",
      "PnL_Points", "RR_Achieved", "HoldBars",
      "TP_Multiplier", "RCR_Regime"
   );

   // Main analysis loop - iterate through each potential session start
   int processedDays = 0;
   datetime lastProcessedDate = 0;

   // Start from oldest data, leave room for lookback
   int startBar = totalBars - InpATR_Period - 50;

   for(int i = startBar; i >= InpMaxBarsAfterOpen + InpMaxHoldBars; i--)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, i);
      MqlDateTime dt;
      TimeToStruct(barTime, dt);

      // Skip if same date already processed for this session
      datetime dateOnly = StringToTime(TimeToString(barTime, TIME_DATE));

      // Check each enabled session
      if(InpUseLondon && IsSessionStart(dt, InpLondonHour, InpLondonMinute))
      {
         if(IsDayEnabled(dt.day_of_week))
         {
            SetupData setup;
            if(AnalyzeSetup(i, "LONDON", setup))
            {
               WriteSetupToCSV(handle, setup);
               UpdateStats(setup);
            }
         }
      }

      if(InpUseNewYork && IsSessionStart(dt, InpNewYorkHour, InpNewYorkMinute))
      {
         if(IsDayEnabled(dt.day_of_week))
         {
            SetupData setup;
            if(AnalyzeSetup(i, "NEWYORK", setup))
            {
               WriteSetupToCSV(handle, setup);
               UpdateStats(setup);
            }
         }
      }

      if(InpUseTokyo && IsSessionStart(dt, InpTokyoHour, InpTokyoMinute))
      {
         if(IsDayEnabled(dt.day_of_week))
         {
            SetupData setup;
            if(AnalyzeSetup(i, "TOKYO", setup))
            {
               WriteSetupToCSV(handle, setup);
               UpdateStats(setup);
            }
         }
      }

      // Progress indicator
      if(i % 5000 == 0)
         Print("Processing bar ", startBar - i, " / ", startBar, " (", 
               DoubleToString((double)(startBar - i) / startBar * 100, 1), "%)");
   }

   // Write summary statistics
   WriteSummary(handle);

   FileClose(handle);

   Print("");
   Print("═══════════════════════════════════════════════════════════");
   Print("   ANALYSIS COMPLETE - CSV saved: ", filename);
   Print("═══════════════════════════════════════════════════════════");
   PrintSummary();
}

//+------------------------------------------------------------------+
//| Check if current bar is session start                             |
//+------------------------------------------------------------------+
bool IsSessionStart(const MqlDateTime &dt, int sessionHour, int sessionMinute)
{
   return (dt.hour == sessionHour && dt.min == sessionMinute);
}

//+------------------------------------------------------------------+
//| Check if day of week is enabled                                   |
//+------------------------------------------------------------------+
bool IsDayEnabled(int dayOfWeek)
{
   switch(dayOfWeek)
   {
      case 0: return false;           // Sunday - markets closed
      case 1: return InpMonday;
      case 2: return InpTuesday;
      case 3: return InpWednesday;
      case 4: return InpThursday;
      case 5: return InpFriday;
      case 6: return false;           // Saturday - markets closed
   }
   return false;
}

//+------------------------------------------------------------------+
//| Analyze a potential setup                                         |
//+------------------------------------------------------------------+
bool AnalyzeSetup(int sessionStartBar, string sessionName, SetupData &setup)
{
   // Initialize setup
   ZeroMemory(setup);
   setup.setupTime = iTime(_Symbol, PERIOD_M5, sessionStartBar);
   setup.session = sessionName;

   MqlDateTime dt;
   TimeToStruct(setup.setupTime, dt);
   setup.dayOfWeek = dt.day_of_week;

   // Calculate range bars needed
   int rangeBars = InpRangeMinutes / 5;  // Convert to M5 bars
   int rangeStartBar = sessionStartBar + rangeBars;

   // Safety check
   if(rangeStartBar >= iBars(_Symbol, PERIOD_M5) - InpATR_Period)
      return false;

   // Calculate range High/Low/Open/Close
   double rangeHigh = iHigh(_Symbol, PERIOD_M5, sessionStartBar + 1);  // First bar of range
   double rangeLow = iLow(_Symbol, PERIOD_M5, sessionStartBar + 1);
   double rangeOpen = iOpen(_Symbol, PERIOD_M5, rangeStartBar);        // Oldest bar of range
   double rangeClose = iClose(_Symbol, PERIOD_M5, sessionStartBar + 1); // Newest bar of range

   for(int j = sessionStartBar + 1; j <= rangeStartBar; j++)
   {
      double h = iHigh(_Symbol, PERIOD_M5, j);
      double l = iLow(_Symbol, PERIOD_M5, j);
      if(h > rangeHigh) rangeHigh = h;
      if(l < rangeLow) rangeLow = l;
   }

   setup.rangeHigh = rangeHigh;
   setup.rangeLow = rangeLow;
   setup.rangeOpen = rangeOpen;
   setup.rangeClose = rangeClose;
   setup.rangeSize = rangeHigh - rangeLow;

   // Validate range size
   if(setup.rangeSize <= 0 || setup.rangeSize < _Point * 10)
      return false;

   // Calculate ATR (using D1 for daily context)
   double atr = CalculateATR(sessionStartBar);
   if(atr <= 0)
      return false;
   setup.ATR = atr;

   //--- FILTER 1: RCR (Range Compression Ratio) ---
   setup.RCR = setup.rangeSize / atr;
   setup.RCR_pass = (setup.RCR < InpRCR_MaxThreshold);

   //--- FILTER 2: DBI (Directional Bias Index) ---
   // DBI = (Close - Open) / (High - Low)
   // Ranges from -1 (bearish, close at low) to +1 (bullish, close at high)
   setup.DBI = (rangeClose - rangeOpen) / setup.rangeSize;
   setup.DBI_pass = (MathAbs(setup.DBI) > InpDBI_Threshold);  // Has directional bias

   //--- FILTER 3: MPS (Momentum Persistence Score) ---
   setup.MPS = CalculateMPS(sessionStartBar + 1, InpMPS_Lookback);
   // MPS_pass depends on alignment with DBI
   if(setup.DBI > 0)
      setup.MPS_pass = (setup.MPS > InpMPS_Threshold);  // Bullish momentum for bullish bias
   else if(setup.DBI < 0)
      setup.MPS_pass = (setup.MPS < (1.0 - InpMPS_Threshold));  // Bearish momentum for bearish bias
   else
      setup.MPS_pass = false;  // No clear direction

   //--- Combined filter result ---
   setup.allFiltersPass = setup.RCR_pass && setup.DBI_pass && setup.MPS_pass;

   //--- BREAKOUT DETECTION ---
   double breakoutBufferPoints = atr * InpBreakoutBuffer;
   double longEntry = rangeHigh + breakoutBufferPoints;
   double shortEntry = rangeLow - breakoutBufferPoints;

   setup.breakoutOccurred = false;
   setup.breakoutDirection = 0;

   // Look for breakout in next N bars
   for(int k = sessionStartBar; k >= sessionStartBar - InpMaxBarsAfterOpen && k >= 0; k--)
   {
      double high = iHigh(_Symbol, PERIOD_M5, k);
      double low = iLow(_Symbol, PERIOD_M5, k);

      // Check for long breakout
      if(high >= longEntry && setup.DBI >= 0)
      {
         setup.breakoutOccurred = true;
         setup.breakoutDirection = 1;
         setup.breakoutPrice = longEntry;
         setup.breakoutTime = iTime(_Symbol, PERIOD_M5, k);
         setup.barsToBreakout = sessionStartBar - k;
         setup.entryPrice = longEntry;
         break;
      }

      // Check for short breakout
      if(low <= shortEntry && setup.DBI <= 0)
      {
         setup.breakoutOccurred = true;
         setup.breakoutDirection = -1;
         setup.breakoutPrice = shortEntry;
         setup.breakoutTime = iTime(_Symbol, PERIOD_M5, k);
         setup.barsToBreakout = sessionStartBar - k;
         setup.entryPrice = shortEntry;
         break;
      }
   }

   //--- OUTCOME MEASUREMENT ---
   if(!setup.breakoutOccurred)
   {
      setup.exitReason = "NO_BREAKOUT";
      setup.pnlPoints = 0;
      setup.RR_achieved = 0;
   }
   else
   {
      // Determine TP multiplier based on RCR regime
      double tpMult;
      string rcr_regime;
      if(setup.RCR < 0.5)
      {
         tpMult = InpTP_Mult_High;  // High compression = larger TP
         rcr_regime = "HIGH_COMPRESSION";
      }
      else if(setup.RCR < 0.8)
      {
         tpMult = InpTP_Mult_Mid;
         rcr_regime = "MID_COMPRESSION";
      }
      else
      {
         tpMult = InpTP_Mult_Low;
         rcr_regime = "LOW_COMPRESSION";
      }

      // Calculate TP and SL
      double risk = setup.rangeSize * InpSL_Mult;
      double reward = setup.rangeSize * tpMult;

      if(setup.breakoutDirection == 1)  // Long
      {
         setup.TP = setup.entryPrice + reward;
         setup.SL = setup.entryPrice - risk;
      }
      else  // Short
      {
         setup.TP = setup.entryPrice - reward;
         setup.SL = setup.entryPrice + risk;
      }

      // Simulate trade outcome
      int entryBar = sessionStartBar - setup.barsToBreakout;
      SimulateTradeOutcome(entryBar, setup);
   }

   g_totalSetups++;
   return true;
}

//+------------------------------------------------------------------+
//| Calculate ATR using M5 bars (convert to daily equivalent)        |
//+------------------------------------------------------------------+
double CalculateATR(int barIndex)
{
   // Calculate ATR over InpATR_Period days worth of M5 bars
   int barsPerDay = 288;  // 24 hours * 12 bars per hour
   int lookbackBars = InpATR_Period * barsPerDay;

   // Simplified: use H1 for ATR calculation
   int h1Bar = iBarShift(_Symbol, PERIOD_H1, iTime(_Symbol, PERIOD_M5, barIndex));
   if(h1Bar < 0 || h1Bar + InpATR_Period >= iBars(_Symbol, PERIOD_H1))
      return 0;

   double atrSum = 0;
   for(int i = 0; i < InpATR_Period; i++)
   {
      double high = iHigh(_Symbol, PERIOD_H1, h1Bar + i);
      double low = iLow(_Symbol, PERIOD_H1, h1Bar + i);
      double prevClose = iClose(_Symbol, PERIOD_H1, h1Bar + i + 1);

      double tr = MathMax(high - low, MathMax(MathAbs(high - prevClose), MathAbs(low - prevClose)));
      atrSum += tr;
   }

   return atrSum / InpATR_Period;
}

//+------------------------------------------------------------------+
//| Calculate MPS (Momentum Persistence Score)                        |
//+------------------------------------------------------------------+
double CalculateMPS(int startBar, int lookback)
{
   // MPS = weighted sum of bullish candles / total weight
   // More recent candles have higher weight (recency bias)

   double weightedBullish = 0;
   double totalWeight = 0;

   for(int i = 0; i < lookback && (startBar + i) < iBars(_Symbol, PERIOD_M5); i++)
   {
      double open = iOpen(_Symbol, PERIOD_M5, startBar + i);
      double close = iClose(_Symbol, PERIOD_M5, startBar + i);

      // Weight decreases with age (recency bias)
      double weight = (double)(lookback - i) / lookback;
      weight = weight * weight;  // Quadratic decay

      if(close > open)
         weightedBullish += weight;

      totalWeight += weight;
   }

   if(totalWeight == 0)
      return 0.5;

   return weightedBullish / totalWeight;
}

//+------------------------------------------------------------------+
//| Simulate trade outcome                                            |
//+------------------------------------------------------------------+
void SimulateTradeOutcome(int entryBar, SetupData &setup)
{
   setup.holdBars = 0;

   for(int k = entryBar - 1; k >= entryBar - InpMaxHoldBars && k >= 0; k--)
   {
      setup.holdBars++;
      double high = iHigh(_Symbol, PERIOD_M5, k);
      double low = iLow(_Symbol, PERIOD_M5, k);

      if(setup.breakoutDirection == 1)  // Long
      {
         // Check SL first (conservative)
         if(low <= setup.SL)
         {
            setup.exitPrice = setup.SL;
            setup.exitReason = "SL";
            setup.pnlPoints = (setup.SL - setup.entryPrice) / _Point;
            setup.RR_achieved = -1.0;
            return;
         }
         // Check TP
         if(high >= setup.TP)
         {
            setup.exitPrice = setup.TP;
            setup.exitReason = "TP";
            setup.pnlPoints = (setup.TP - setup.entryPrice) / _Point;
            setup.RR_achieved = setup.pnlPoints / ((setup.entryPrice - setup.SL) / _Point);
            return;
         }
      }
      else  // Short
      {
         // Check SL first
         if(high >= setup.SL)
         {
            setup.exitPrice = setup.SL;
            setup.exitReason = "SL";
            setup.pnlPoints = (setup.entryPrice - setup.SL) / _Point;
            setup.RR_achieved = -1.0;
            return;
         }
         // Check TP
         if(low <= setup.TP)
         {
            setup.exitPrice = setup.TP;
            setup.exitReason = "TP";
            setup.pnlPoints = (setup.entryPrice - setup.TP) / _Point;
            setup.RR_achieved = setup.pnlPoints / ((setup.SL - setup.entryPrice) / _Point);
            return;
         }
      }
   }

   // Timeout - close at last bar close
   int lastBar = MathMax(0, entryBar - InpMaxHoldBars);
   setup.exitPrice = iClose(_Symbol, PERIOD_M5, lastBar);
   setup.exitReason = "TIMEOUT";

   if(setup.breakoutDirection == 1)
      setup.pnlPoints = (setup.exitPrice - setup.entryPrice) / _Point;
   else
      setup.pnlPoints = (setup.entryPrice - setup.exitPrice) / _Point;

   setup.RR_achieved = setup.pnlPoints / ((MathAbs(setup.entryPrice - setup.SL)) / _Point);
}

//+------------------------------------------------------------------+
//| Write setup data to CSV                                           |
//+------------------------------------------------------------------+
void WriteSetupToCSV(int handle, const SetupData &setup)
{
   string dayName = "";
   switch(setup.dayOfWeek)
   {
      case 1: dayName = "Monday"; break;
      case 2: dayName = "Tuesday"; break;
      case 3: dayName = "Wednesday"; break;
      case 4: dayName = "Thursday"; break;
      case 5: dayName = "Friday"; break;
      default: dayName = "Weekend"; break;
   }

   // Determine RCR regime
   string rcr_regime;
   double tp_mult;
   if(setup.RCR < 0.5)
   {
      rcr_regime = "HIGH_COMP";
      tp_mult = InpTP_Mult_High;
   }
   else if(setup.RCR < 0.8)
   {
      rcr_regime = "MID_COMP";
      tp_mult = InpTP_Mult_Mid;
   }
   else
   {
      rcr_regime = "LOW_COMP";
      tp_mult = InpTP_Mult_Low;
   }

   FileWrite(handle,
      TimeToString(setup.setupTime, TIME_DATE|TIME_MINUTES),
      setup.session,
      IntegerToString(setup.dayOfWeek),
      dayName,
      DoubleToString(setup.rangeHigh, _Digits),
      DoubleToString(setup.rangeLow, _Digits),
      DoubleToString(setup.rangeSize / _Point, 1),
      DoubleToString(setup.rangeOpen, _Digits),
      DoubleToString(setup.rangeClose, _Digits),
      DoubleToString(setup.ATR / _Point, 1),
      DoubleToString(setup.RCR, 3),
      DoubleToString(setup.DBI, 3),
      DoubleToString(setup.MPS, 3),
      setup.RCR_pass ? "PASS" : "FAIL",
      setup.DBI_pass ? "PASS" : "FAIL",
      setup.MPS_pass ? "PASS" : "FAIL",
      setup.allFiltersPass ? "PASS" : "FAIL",
      setup.breakoutOccurred ? "YES" : "NO",
      setup.breakoutDirection == 1 ? "LONG" : (setup.breakoutDirection == -1 ? "SHORT" : "NONE"),
      DoubleToString(setup.breakoutPrice, _Digits),
      IntegerToString(setup.barsToBreakout),
      DoubleToString(setup.entryPrice, _Digits),
      DoubleToString(setup.TP, _Digits),
      DoubleToString(setup.SL, _Digits),
      DoubleToString(setup.exitPrice, _Digits),
      setup.exitReason,
      DoubleToString(setup.pnlPoints, 1),
      DoubleToString(setup.RR_achieved, 2),
      IntegerToString(setup.holdBars),
      DoubleToString(tp_mult, 1),
      rcr_regime
   );
}

//+------------------------------------------------------------------+
//| Update statistics                                                 |
//+------------------------------------------------------------------+
void UpdateStats(const SetupData &setup)
{
   // Update day of week stats
   g_daySetups[setup.dayOfWeek]++;

   // Only count trades that had breakout
   if(!setup.breakoutOccurred)
   {
      g_noBreakout++;
      return;
   }

   // Session stats
   if(setup.session == "LONDON")
   {
      g_londonSetups++;
      if(setup.exitReason == "TP") g_londonWins++;
   }
   else if(setup.session == "NEWYORK")
   {
      g_nySetups++;
      if(setup.exitReason == "TP") g_nyWins++;
   }
   else if(setup.session == "TOKYO")
   {
      g_tokyoSetups++;
      if(setup.exitReason == "TP") g_tokyoWins++;
   }

   // Direction stats
   if(setup.breakoutDirection == 1)
   {
      g_longSetups++;
      if(setup.exitReason == "TP") g_longWins++;
   }
   else
   {
      g_shortSetups++;
      if(setup.exitReason == "TP") g_shortWins++;
   }

   // Day wins
   if(setup.exitReason == "TP")
      g_dayWins[setup.dayOfWeek]++;

   // RCR regime stats
   if(setup.RCR < 0.5)
   {
      g_highRCR_setups++;
      if(setup.exitReason == "TP") g_highRCR_wins++;
   }
   else if(setup.RCR < 0.8)
   {
      g_midRCR_setups++;
      if(setup.exitReason == "TP") g_midRCR_wins++;
   }
   else
   {
      g_lowRCR_setups++;
      if(setup.exitReason == "TP") g_lowRCR_wins++;
   }

   // Overall stats
   if(setup.exitReason == "TP")
   {
      g_wins++;
      g_totalProfit += setup.pnlPoints;
   }
   else if(setup.exitReason == "SL")
   {
      g_losses++;
      g_totalLoss += MathAbs(setup.pnlPoints);
   }
   else if(setup.exitReason == "TIMEOUT")
   {
      g_timeouts++;
      if(setup.pnlPoints >= 0)
         g_totalProfit += setup.pnlPoints;
      else
         g_totalLoss += MathAbs(setup.pnlPoints);
   }

   // Drawdown tracking
   g_runningPnL += setup.pnlPoints;
   if(g_runningPnL > g_peakPnL)
      g_peakPnL = g_runningPnL;
   double dd = g_peakPnL - g_runningPnL;
   if(dd > g_maxDrawdown)
      g_maxDrawdown = dd;
}

