   double profitFactor = g_totalLoss > 0 ? g_totalProfit / g_totalLoss : 0;

   FileWrite(handle, "OVERALL");
   FileWrite(handle, "Total Setups Analyzed", g_totalSetups);
   FileWrite(handle, "No Breakout (skipped)", g_noBreakout);
   FileWrite(handle, "Total Trades", totalTrades);
   FileWrite(handle, "Wins (TP)", g_wins);
   FileWrite(handle, "Losses (SL)", g_losses);
   FileWrite(handle, "Timeouts", g_timeouts);
