   FileWrite(handle, "Total Profit (points)", DoubleToString(g_totalProfit, 1));
   FileWrite(handle, "Total Loss (points)", DoubleToString(g_totalLoss, 1));
   FileWrite(handle, "Net PnL (points)", DoubleToString(g_totalProfit - g_totalLoss, 1));
   FileWrite(handle, "Profit Factor", DoubleToString(profitFactor, 2));
   FileWrite(handle, "Max Drawdown (points)", DoubleToString(g_maxDrawdown, 1));
   FileWrite(handle, "");

   FileWrite(handle, "BY SESSION");
   FileWrite(handle, "London Trades", g_londonSetups, "Wins", g_londonWins, 
             "WR%", g_londonSetups > 0 ? DoubleToString((double)g_londonWins/g_londonSetups*100, 1) : "0");
   FileWrite(handle, "New York Trades", g_nySetups, "Wins", g_nyWins,
             "WR%", g_nySetups > 0 ? DoubleToString((double)g_nyWins/g_nySetups*100, 1) : "0");
   FileWrite(handle, "Tokyo Trades", g_tokyoSetups, "Wins", g_tokyoWins,
             "WR%", g_tokyoSetups > 0 ? DoubleToString((double)g_tokyoWins/g_tokyoSetups*100, 1) : "0");
   FileWrite(handle, "");

   FileWrite(handle, "BY DIRECTION");
   FileWrite(handle, "Long Trades", g_longSetups, "Wins", g_longWins,
             "WR%", g_longSetups > 0 ? DoubleToString((double)g_longWins/g_longSetups*100, 1) : "0");
   FileWrite(handle, "Short Trades", g_shortSetups, "Wins", g_shortWins,
             "WR%", g_shortSetups > 0 ? DoubleToString((double)g_shortWins/g_shortSetups*100, 1) : "0");
   FileWrite(handle, "");

   FileWrite(handle, "BY DAY OF WEEK");
   string dayNames[] = {"Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"};
   for(int d = 1; d <= 5; d++)
   {
      double dayWR = g_daySetups[d] > 0 ? (double)g_dayWins[d] / g_daySetups[d] * 100 : 0;
      FileWrite(handle, dayNames[d], "Setups", g_daySetups[d], "Wins", g_dayWins[d], 
                "WR%", DoubleToString(dayWR, 1));
   }
   FileWrite(handle, "");

   FileWrite(handle, "BY RCR REGIME");
   FileWrite(handle, "High Compression (<0.5)", g_highRCR_setups, "Wins", g_highRCR_wins,
             "WR%", g_highRCR_setups > 0 ? DoubleToString((double)g_highRCR_wins/g_highRCR_setups*100, 1) : "0");
   FileWrite(handle, "Mid Compression (0.5-0.8)", g_midRCR_setups, "Wins", g_midRCR_wins,
             "WR%", g_midRCR_setups > 0 ? DoubleToString((double)g_midRCR_wins/g_midRCR_setups*100, 1) : "0");
   FileWrite(handle, "Low Compression (>0.8)", g_lowRCR_setups, "Wins", g_lowRCR_wins,
             "WR%", g_lowRCR_setups > 0 ? DoubleToString((double)g_lowRCR_wins/g_lowRCR_setups*100, 1) : "0");
}

