//|  - Sesiones: London + NY (Tokyo descartado PF=0.32)             |
//|  - Días: Martes (ambas), Miércoles+Jueves (solo NY)             |
//|  - Dirección: SHORT only (LONG PF<1.0 consistentemente)         |
//|  - Filtro: RCR < 1.5 (compresión de rango)                      |
//|                                                                  |
//|  Author: Jose - Quant Trading Development                        |
//+------------------------------------------------------------------+
#property copyright "Jose - Quant Trading"
#property version   "1.00"
#property strict
#property description "ARM-EA: Breakout SHORT strategy for GBPUSD"
#property description "Validated IS/OOS with 8 years of data"

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "══════════ ESTRATEGIA ══════════"
input int      InpRangeMinutes      = 60;        // Duración del rango (minutos)
input double   InpRCR_Max           = 1.50;      // RCR máximo (filtro de compresión)
input double   InpBreakoutBuffer    = 0.20;      // Buffer de breakout (ATR multiplier)
input int      InpATR_Period        = 14;        // Período ATR

input group "══════════ SESIÓN LONDON ══════════"
input bool     InpUseLondon         = true;      // Activar sesión London
input int      InpLondonHour        = 8;         // Hora inicio London (broker)
input int      InpLondonMinute      = 0;         // Minuto inicio London

input group "══════════ SESIÓN NEW YORK ══════════"
input bool     InpUseNewYork        = true;      // Activar sesión New York
input int      InpNewYorkHour       = 13;        // Hora inicio NY (broker)
input int      InpNewYorkMinute     = 30;        // Minuto inicio NY

input group "══════════ DÍAS ACTIVOS ══════════"
input bool     InpMonday            = false;     // Lunes (desactivado - ruido post-weekend)
input bool     InpTuesday           = true;      // Martes ✓ (mejor día - PF 1.28)
input bool     InpWednesday         = true;      // Miércoles (solo NY - ver abajo)
input bool     InpThursday          = true;      // Jueves (solo NY - ver abajo)
input bool     InpFriday            = false;     // Viernes (desactivado - overfit OOS)
input bool     InpWedThuOnlyNY      = true;      // Wed+Thu solo en NY (no London)

input group "══════════ TARGETS ══════════"
input double   InpTP_Multiplier     = 2.00;      // TP = X * rango (default 2.0)
input double   InpSL_Multiplier     = 1.00;      // SL = X * rango (default 1.0)
input int      InpMaxHoldBars       = 48;        // Max bars en posición (M5 = 4 horas)
input int      InpMaxBarsBreakout   = 24;        // Max bars para breakout (M5 = 2 horas)

input group "══════════ BREAKEVEN ══════════"
input bool     InpUseBE             = true;      // Usar breakeven
input double   InpBE_Trigger        = 50.0;      // Activar BE al X% del TP
input int      InpBE_LockPips       = 5;         // Pips de ganancia asegurada

input group "══════════ GESTIÓN DE RIESGO ══════════"
input double   InpRiskPercent       = 0.50;      // Riesgo por trade (% del balance)
input double   InpMaxLots           = 5.00;      // Lotes máximos
input int      InpMaxDailyTrades    = 2;         // Trades máximos por día
input double   InpDailyLossLimit    = 3.00;      // Límite pérdida diaria (%)
input double   InpMaxDrawdown       = 6.00;      // Drawdown máximo total (%)

input group "══════════ IDENTIFICACIÓN ══════════"
input int      InpMagicNumber       = 20260406;  // Magic number
input string   InpComment           = "ARM_EA";  // Comentario de órdenes

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         trade;
CPositionInfo  posInfo;

// Estado del EA
bool           g_rangeCalculated = false;
double         g_rangeHigh = 0;
double         g_rangeLow = 0;
double         g_rangeSize = 0;
double         g_rangeATR = 0;
double         g_RCR = 0;
datetime       g_rangeTime = 0;
string         g_currentSession = "";
bool           g_waitingBreakout = false;
int            g_barsWaiting = 0;

// Control diario
int            g_dailyTrades = 0;
double         g_dailyPnL = 0;
datetime       g_lastTradeDay = 0;
double         g_initialBalance = 0;
double         g_peakBalance = 0;

// Gestión de posición
datetime       g_entryTime = 0;
int            g_holdBars = 0;
bool           g_beActivated = false;

//+------------------------------------------------------------------+
//| Expert initialization function                                    |
//+------------------------------------------------------------------+
int OnInit()
{
   // Validar símbolo
   if(StringFind(_Symbol, "GBP") < 0)
   {
      Print("⚠️ ARM-EA está optimizado para GBPUSD. Usar en otros pares bajo tu propio riesgo.");
   }

   // Validar timeframe
   if(_Period != PERIOD_M5)
   {
      Print("❌ ERROR: ARM-EA requiere timeframe M5");
      return INIT_FAILED;
   }

   // Configurar trade
   trade.SetExpertMagicNumber(InpMagicNumber);
   trade.SetDeviationInPoints(10);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   // Inicializar variables
   g_initialBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   g_peakBalance = g_initialBalance;

   ResetDailyCounters();

   Print("═══════════════════════════════════════════════════════════");
   Print("   ARM-EA v1.0 inicializado en ", _Symbol);
   Print("   Configuración: LON+NY, Tue(ambas), Wed+Thu(solo NY), SHORT only");
   Print("   Validación: IS PF=1.11 → OOS PF=1.58 (Ratio 1.42)");
   Print("═══════════════════════════════════════════════════════════");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                  |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   Print("ARM-EA detenido. Daily PnL: ", DoubleToString(g_dailyPnL, 2));
}

//+------------------------------------------------------------------+
//| Expert tick function                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   // Control de nueva barra
   static datetime lastBarTime = 0;
   datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);

   if(currentBarTime == lastBarTime)
      return;  // Solo procesar en nueva barra

   lastBarTime = currentBarTime;

   // Reset diario
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   if(today != g_lastTradeDay)
   {
      ResetDailyCounters();
      g_lastTradeDay = today;
   }

   // Verificar drawdown total
   if(!CheckDrawdown())
      return;

   // Verificar límite de pérdida diaria
   if(!CheckDailyLoss())
      return;

   // Gestionar posición abierta
   if(HasOpenPosition())
   {
      ManagePosition();
      return;
   }

   // Verificar límite de trades diarios
   if(g_dailyTrades >= InpMaxDailyTrades)
      return;

   // ¿Es hora de calcular un nuevo rango?
   if(IsSessionStart(dt))
   {
      CalculateRange(dt);
   }

   // ¿Estamos esperando breakout?
   if(g_waitingBreakout)
   {
      g_barsWaiting++;

      if(g_barsWaiting > InpMaxBarsBreakout)
      {
         // Timeout - no hubo breakout
         ResetRangeState();
         return;
      }

      CheckBreakout();
   }
}

//+------------------------------------------------------------------+
//| Check if it's session start time                                  |
//+------------------------------------------------------------------+
bool IsSessionStart(const MqlDateTime &dt)
{
   // Verificar día de la semana
   if(!IsDayEnabled(dt.day_of_week))
      return false;

   // London session start
   if(InpUseLondon && dt.hour == InpLondonHour && dt.min == InpLondonMinute)
   {
      // Wed+Thu solo NY si está activado el filtro
      if(InpWedThuOnlyNY && (dt.day_of_week == 3 || dt.day_of_week == 4))
         return false;

      g_currentSession = "LONDON";
      return true;
   }

   // New York session start
   if(InpUseNewYork && dt.hour == InpNewYorkHour && dt.min == InpNewYorkMinute)
   {
      g_currentSession = "NEWYORK";
      return true;
   }

   return false;
}

//+------------------------------------------------------------------+
//| Check if day is enabled                                           |
//+------------------------------------------------------------------+
bool IsDayEnabled(int dayOfWeek)
{
   switch(dayOfWeek)
   {
      case 0: return false;           // Domingo
      case 1: return InpMonday;
      case 2: return InpTuesday;
      case 3: return InpWednesday;
      case 4: return InpThursday;
      case 5: return InpFriday;
      case 6: return false;           // Sábado
   }
   return false;
}

//+------------------------------------------------------------------+
//| Calculate pre-session range                                       |
//+------------------------------------------------------------------+
void CalculateRange(const MqlDateTime &dt)
{
   int rangeBars = InpRangeMinutes / 5;  // M5 bars

   // Calcular High/Low del rango
   g_rangeHigh = iHigh(_Symbol, PERIOD_M5, 1);
   g_rangeLow = iLow(_Symbol, PERIOD_M5, 1);

   for(int i = 1; i <= rangeBars; i++)
   {
      double h = iHigh(_Symbol, PERIOD_M5, i);
      double l = iLow(_Symbol, PERIOD_M5, i);
      if(h > g_rangeHigh) g_rangeHigh = h;
      if(l < g_rangeLow) g_rangeLow = l;
   }

   g_rangeSize = g_rangeHigh - g_rangeLow;

   // Calcular ATR
   g_rangeATR = CalculateATR();

   // Calcular RCR (Range Compression Ratio)
   g_RCR = (g_rangeATR > 0) ? g_rangeSize / g_rangeATR : 999;

   // Validar filtro RCR
   if(g_RCR > InpRCR_Max)
   {
      Print("❌ RCR=", DoubleToString(g_RCR, 2), " > ", DoubleToString(InpRCR_Max, 2), 
            " - Rango demasiado expandido, skip");
      ResetRangeState();
      return;
   }

   // Validar tamaño mínimo de rango
   if(g_rangeSize < _Point * 50)  // Mínimo 5 pips
   {
      Print("❌ Rango demasiado pequeño: ", DoubleToString(g_rangeSize / _Point, 1), " pts");
      ResetRangeState();
      return;
   }

   g_rangeCalculated = true;
   g_waitingBreakout = true;
   g_barsWaiting = 0;
   g_rangeTime = TimeCurrent();

   Print("═══ RANGO ", g_currentSession, " CALCULADO ═══");
   Print("   High: ", DoubleToString(g_rangeHigh, _Digits));
   Print("   Low:  ", DoubleToString(g_rangeLow, _Digits));
   Print("   Size: ", DoubleToString(g_rangeSize / _Point, 1), " pts");
   Print("   ATR:  ", DoubleToString(g_rangeATR / _Point, 1), " pts");
   Print("   RCR:  ", DoubleToString(g_RCR, 3), " (max ", DoubleToString(InpRCR_Max, 2), ")");
   Print("   Esperando breakout SHORT...");
}

//+------------------------------------------------------------------+
//| Calculate ATR using H1 timeframe                                  |
//+------------------------------------------------------------------+
double CalculateATR()
{
   double atrSum = 0;

   for(int i = 0; i < InpATR_Period; i++)
   {
      double high = iHigh(_Symbol, PERIOD_H1, i);
      double low = iLow(_Symbol, PERIOD_H1, i);
      double prevClose = iClose(_Symbol, PERIOD_H1, i + 1);

      double tr = MathMax(high - low, 
                          MathMax(MathAbs(high - prevClose), 
                                  MathAbs(low - prevClose)));
      atrSum += tr;
   }

   return atrSum / InpATR_Period;
}

//+------------------------------------------------------------------+
//| Check for breakout (SHORT only - validated configuration)        |
//+------------------------------------------------------------------+
void CheckBreakout()
{
   double currentLow = iLow(_Symbol, PERIOD_M5, 0);
   double buffer = g_rangeATR * InpBreakoutBuffer;
   double shortEntry = g_rangeLow - buffer;

   // Solo verificar SHORT breakout (configuración validada)
   if(currentLow <= shortEntry)
   {
      ExecuteShort(shortEntry);
   }
}

//+------------------------------------------------------------------+
//| Execute SHORT trade                                               |
//+------------------------------------------------------------------+
void ExecuteShort(double entryPrice)
{
   // Calcular TP y SL
   double sl = g_rangeHigh + (g_rangeSize * (InpSL_Multiplier - 1.0));
   double tp = entryPrice - (g_rangeSize * InpTP_Multiplier);

   // Normalizar precios
   entryPrice = NormalizeDouble(entryPrice, _Digits);
   sl = NormalizeDouble(sl, _Digits);
   tp = NormalizeDouble(tp, _Digits);

   // Calcular lotes
   double riskAmount = AccountInfoDouble(ACCOUNT_BALANCE) * InpRiskPercent / 100.0;
   double slDistance = MathAbs(sl - entryPrice);
   double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   double lots = riskAmount / (slDistance / tickSize * tickValue);
   lots = MathMin(lots, InpMaxLots);
   lots = NormalizeDouble(lots, 2);

   double minLot = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   if(lots < minLot)
      lots = minLot;

   // Verificar spread
   double spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) * _Point;
   if(spread > g_rangeSize * 0.1)  // Spread > 10% del rango
   {
      Print("⚠️ Spread alto: ", DoubleToString(spread / _Point, 1), " pts - posponiendo");
      return;
   }

   // Ejecutar orden
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

   if(trade.Sell(lots, _Symbol, bid, sl, tp, InpComment))
   {
      g_dailyTrades++;
      g_entryTime = TimeCurrent();
      g_holdBars = 0;
      g_beActivated = false;

      Print("═══ SHORT EJECUTADO ═══");
      Print("   Session: ", g_currentSession);
      Print("   Entry:   ", DoubleToString(bid, _Digits));
      Print("   SL:      ", DoubleToString(sl, _Digits), " (", DoubleToString((sl - bid) / _Point, 1), " pts)");
      Print("   TP:      ", DoubleToString(tp, _Digits), " (", DoubleToString((bid - tp) / _Point, 1), " pts)");
      Print("   Lots:    ", DoubleToString(lots, 2));
      Print("   RCR:     ", DoubleToString(g_RCR, 3));

      ResetRangeState();
   }
   else
   {
      Print("❌ Error al ejecutar SHORT: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Check if we have an open position                                 |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(posInfo.SelectByIndex(i))
      {
         if(posInfo.Magic() == InpMagicNumber && posInfo.Symbol() == _Symbol)
            return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
//| Manage open position                                              |
//+------------------------------------------------------------------+
void ManagePosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!posInfo.SelectByIndex(i))
         continue;

      if(posInfo.Magic() != InpMagicNumber || posInfo.Symbol() != _Symbol)
         continue;

      g_holdBars++;

      double currentPrice = posInfo.PriceCurrent();
      double openPrice = posInfo.PriceOpen();
      double sl = posInfo.StopLoss();
      double tp = posInfo.TakeProfit();
      double profit = posInfo.Profit();

      // Timeout por máximo de barras
      if(g_holdBars >= InpMaxHoldBars)
      {
         Print("⏰ TIMEOUT - cerrando por máximo de barras (", g_holdBars, ")");
         trade.PositionClose(posInfo.Ticket());
         UpdateDailyPnL(profit);
         return;
      }

      // Breakeven management
      if(InpUseBE && !g_beActivated && posInfo.PositionType() == POSITION_TYPE_SELL)
      {
         double targetMove = MathAbs(openPrice - tp) * (InpBE_Trigger / 100.0);
         double currentMove = openPrice - currentPrice;

         if(currentMove >= targetMove)
         {
            double newSL = openPrice - (InpBE_LockPips * _Point * 10);
            newSL = NormalizeDouble(newSL, _Digits);

            if(newSL < sl)
            {
               if(trade.PositionModify(posInfo.Ticket(), newSL, tp))
               {
                  g_beActivated = true;
                  Print("✓ Breakeven activado a ", DoubleToString(newSL, _Digits));
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Reset daily counters                                              |
//+------------------------------------------------------------------+
void ResetDailyCounters()
{
   g_dailyTrades = 0;
   g_dailyPnL = 0;
   ResetRangeState();
   Print("📅 Nuevo día - contadores reiniciados");
}

//+------------------------------------------------------------------+
//| Reset range state                                                 |
//+------------------------------------------------------------------+
void ResetRangeState()
{
   g_rangeCalculated = false;
   g_waitingBreakout = false;
   g_barsWaiting = 0;
   g_rangeHigh = 0;
   g_rangeLow = 0;
   g_rangeSize = 0;
   g_currentSession = "";
}

//+------------------------------------------------------------------+
//| Update daily PnL                                                  |
//+------------------------------------------------------------------+
void UpdateDailyPnL(double tradePnL)
{
   g_dailyPnL += tradePnL;

   // Actualizar peak balance
   double currentBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   if(currentBalance > g_peakBalance)
      g_peakBalance = currentBalance;
}

//+------------------------------------------------------------------+
//| Check daily loss limit                                            |
//+------------------------------------------------------------------+
bool CheckDailyLoss()
{
   double dailyLossPercent = (g_dailyPnL / g_initialBalance) * 100.0;

   if(dailyLossPercent < -InpDailyLossLimit)
   {
      Print("⛔ Límite de pérdida diaria alcanzado: ", DoubleToString(dailyLossPercent, 2), "%");
      return false;
   }

   return true;
}

//+------------------------------------------------------------------+
//| Check total drawdown                                              |
//+------------------------------------------------------------------+
bool CheckDrawdown()
{
   double currentBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   double drawdown = ((g_peakBalance - currentBalance) / g_peakBalance) * 100.0;

   if(drawdown > InpMaxDrawdown)
   {
      Print("⛔ Drawdown máximo alcanzado: ", DoubleToString(drawdown, 2), "%");
      return false;
   }

   return true;
}

//+------------------------------------------------------------------+
//| OnTradeTransaction - track closed positions                       |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest &request,
                        const MqlTradeResult &result)
{
   if(trans.type == TRADE_TRANSACTION_DEAL_ADD)
   {
      if(trans.deal_type == DEAL_TYPE_SELL || trans.deal_type == DEAL_TYPE_BUY)
      {
         // Verificar si es cierre de nuestra posición
         ulong deal = trans.deal;
         if(HistoryDealSelect(deal))
         {
            if(HistoryDealGetInteger(deal, DEAL_MAGIC) == InpMagicNumber)
            {
               if(HistoryDealGetInteger(deal, DEAL_ENTRY) == DEAL_ENTRY_OUT)
               {
                  double profit = HistoryDealGetDouble(deal, DEAL_PROFIT);
                  UpdateDailyPnL(profit);

                  string exitType = profit > 0 ? "✅ TP" : "❌ SL";
                  Print(exitType, " | Profit: ", DoubleToString(profit, 2), 
                        " | Daily: ", DoubleToString(g_dailyPnL, 2));
               }
            }
         }
      }
   }
}
